void record_intr(uint64 intr) {
    if(intr >= MAXINTR) {
        return;
    }
    intrcnt[intr]++;
}

void
procinit(void)
{
  struct proc *p;
  PCB_Q_ALL_INIT();
  atomic_set(&nextpid, 1);
  // initlock(&pid_lock, "nextpid");
  initlock(&wait_lock, "wait_lock");


  for(p = proc; p < &proc[NPROC]; p++) {
      initlock(&p->lock, "proc");
      initlock(&p->lth_exitlock, "lth_exitlock");
      p->ktime = 0;
      p->utime = 0;
      p->state = UNUSED;
      p->kstack = KSTACK((int) (p - proc));
      INIT_LIST_HEAD(&p->state_list);
      INIT_LIST_HEAD(&p->sibling_list);

      queue_push_back_atomic(&unused_p_q, p);

      // mm_init(&p->mm);
  }


  // Info("========= Information of proc table and tcb table ==========\n");
  // Info("number of proc : %d\n", NPROC);
  // Info("proc table init [ok]\n");

  return;
}

void delete_child(struct proc *parent, struct proc *child) {
    if (nosibling(child)) {
        parent->first_child = NULL;
    } else {
        struct proc *firstchild = firstchild(parent);
        if (child == firstchild) {
            parent->first_child = nextsibling(firstchild);
        }
        list_del_reinit(&child->sibling_list);
    }
}

void append_child(struct proc *parent, struct proc *child) {
    if (nochildren(parent)) {
        parent->first_child = child;
    } else {
        list_add_tail(&child->sibling_list, &(firstchild(parent)->sibling_list));
    }
}

void thread_mapstacks(pagetable_t kpgtbl)
{
  struct tcb *t;

  for(t = tcb_pool;  t < &tcb_pool[NTHREADS]; t++) {
    // !!! here just allocate one page for each thread's kernel stack
    // but map it to KSTACK_PAGE * PGSIZE!!!!
    char *pa = NULL;
    uint64 va = KSTACK((int) (t - tcb_pool));
    for(int i = 0; i < KSTACK_PAGE; i++) {
      if((pa = (char*)kzalloc()) == NULL) {
        panic("thread_mapstacks: kstack alloc failed");
      }
#ifdef __ARCH_RISCV
      if(mappages(kpgtbl, va + i * PGSIZE, PGSIZE, (uint64)pa, PTE_R | PTE_W) < 0) {
        panic("thread_mapstacks: mappages failed");
      }
#else 
      if(mappages(kpgtbl, va + i * PGSIZE, PGSIZE, (uint64)pa, PTE_P | PTE_W | PTE_MAT | PTE_D) < 0) {
        panic("thread_mapstacks: mappages failed");
      }
#endif
    }
#ifdef __DEBUG_THREAD_MAPSTACKS
    Log("thread %d map with kstack base %p, kstack top %p", t - tcb_pool + 1, va + KSTACK_PAGE * PGSIZE , va);
#endif
  }
}

