static void init_rlimit(struct rlimit *rlim) {
    rlim->rlim_cur = RLIM_INFINITY;
    rlim->rlim_max = RLIM_INFINITY;
}

static struct proc*
allocproc(void)
{
  struct proc *p;

  if((p = (struct proc*)queue_pop_atomic(&unused_p_q, 1)) == NULL)
    return NULL;

  acquire(&p->lock);

// found:
  p->pid = allocpid();
  p->pgid = p->pid; // process group id, equals to pid
#ifdef __DEBUG_ALLOCATE_PROC
  Info("proc %d allocated, pcb %p\n", p->pid, p);
#endif
  pcb_q_change_state(p, USED);
  // process family tree
  p->first_child = NULL;
  INIT_LIST_HEAD(&p->sibling_list);

  // thread group
  tginit(&p->tg);

  // timer
  p->utime = 0;
  p->ktime = 0;

  strcpy(p->cinfo.path, "/");
  // state
  // mm_struct
  initlock(&p->mm.lock, "mm_lock");
  p->mm.pagetable = proc_pagetable(p);
#ifdef __DEBUG_ALLOCATE_PROC
  Info("proc %d's pagetable = %p\n", p->pid, p->mm.pagetable);
#endif
  INIT_LIST_HEAD(&p->mm.vma_list);
  p->mm.max_vma = MMAP_MAX_ADDR_START;

  memset(p->rlim, 0, sizeof(p->rlim));
  for (int i = 0; i < RLIM_NLIMITS; i++) {
      init_rlimit(&p->rlim[i]);
  }
  p->ofile_cnt = 0;

  return p;
}

struct proc *create_proc() {
    struct tcb *t = NULL;
    struct proc *p = NULL;

    if ((p = allocproc()) == 0) {
        return 0;
    }

    if ((t = alloc_thread(thread_forkret)) == 0) {
        freeproc(p);
        return 0;
    }

    proc_join_thread(p, t, NULL);

    release(&t->lock);

    return p;
}

void freeproc(struct proc *p)
{

// no trapframe anymore in a process
  // if(p->trapframe)
  //   kfree((void*)p->trapframe);
  // p->trapframe = 0;


#ifdef __DEBUG_FREEPROC
  Log("thread %d freeproc %d", mythread()->tid, cur_proc->pid);
#endif

  // struct tcb  *cur_thread = mythread();
  struct proc *cur_proc = myproc();
  /**
   * acturally, we needn't to free the threads here,
   * because we have freed them in thread_exit
   * and the only entry to proc_exit() is last thread's thread_exit()
   * so we needn't to free them again if we have freed them in thread_exit
   * we just need to wait for the last thread to exit before free the process
   * 
   */
  acquire(&p->lth_exitlock);
  struct tcb *t, *tt;
  acquire(&cur_proc->tg.lock);

  // sometimes it is not from the last thread's thread_exit
  list_for_each_entry_safe(t, tt, &(p->tg.threads), threads) {
    // TODO: is it right?
    if(t)
      list_del_reinit(&t->threads);

    if(!atomic_dec_return(&cur_proc->tg.thread_cnt)) {
      panic("thread count error\n");
    }
    free_thread(t);
  }
  release(&cur_proc->tg.lock);

  // have unmmaped threads' trapframe in free_thread
  // so needn't free them again
  if(p->mm.pagetable)
    proc_freepagetable(p->mm.pagetable, p->sz, 0);
  // the list??
  p->tg.group_leader = NULL;
  p->mm.pagetable = 0;
  p->sz = 0;
  p->pid = 0;
  p->pgid = 0; // process group id, equals to pid

  p->parent = 0;
  p->name[0] = 0;
  // p->chan = 0;
  p->killed = 0;
  p->xstate = 0;
  p->utime = 0;
  p->ktime = 0;
  p->ofile_cnt = 0;
  memset(p->rlim, 0, sizeof(p->rlim));
  // p->state = UNUSED;
  // change to UNUSED state
  pcb_q_change_state(p, UNUSED);
  release(&p->lth_exitlock);
#ifdef __DEBUG_FREEPROC
  Log("thread %d freeproc %d end", mythread()->tid, cur_proc->pid);
#endif
}

pagetable_t
proc_pagetable(struct proc *p)
{
  pagetable_t pagetable;

  // An empty page table.
  pagetable = uvmcreate();
  if(pagetable == 0)
  return 0;

#ifdef __ARCH_RISCV
  // map the trampoline code (for system call return)
  // at the highest user virtual address.
  // only the supervisor uses it, on the way
  // to/from user space, so not PTE_U.
  if(mappages(pagetable, TRAMPOLINE, PGSIZE,
              (uint64)trampoline, PTE_R | PTE_X) < 0){
    Warn("mappages failed, trampoline : %p", (uint64)trampoline);
    Warn("freepages: %d", freemem_pages());
    Warn("total freeram: %p", totalram_bytes());
    uvmfree(pagetable, 0);
    return 0;
  }

  if(mappages(pagetable, SIGRETURN, PGSIZE, (uint64) __user_rt_sigreturn, PTE_R | PTE_X | PTE_U) < 0){
    uvmfree(pagetable, 0);
    return 0;
  }
#else 
    // map the trampoline code (for system call return)
  // at the highest user virtual address.
  // only the supervisor uses it, on the way
  // to/from user space, so not PTE_U.
  if(mappages(pagetable, TRAMPOLINE, PGSIZE,
              (uint64)trampoline, PTE_P | PTE_W | PTE_MAT | PTE_D) < 0){
    uvmfree(pagetable, 0);
    return 0;
  }

  if(mappages(pagetable, SIGRETURN, PGSIZE, (uint64) __user_rt_sigreturn, PTE_P | PTE_W | PTE_MAT | PTE_D | PTE_U) < 0){
    uvmfree(pagetable, 0);
    return 0;
  }
#endif
  // printf_green("trampoline : %p, __user_rt_sigreturn %p", (uint64)trampoline, (uint64) __user_rt_sigreturn);
  // map the trapframe page just below the trampoline page, for
  // trampoline.S.
  // if(mappages(pagetable, TRAPFRAME, PGSIZE,
  //             (uint64)(p->trapframe), PTE_R | PTE_W) < 0){
  //   uvmunmap(pagetable, TRAMPOLINE, 1, 0);
  //   uvmfree(pagetable, 0);
  //   return 0; 
  // }

  return pagetable;
}

void
proc_freepagetable(pagetable_t pagetable, uint64 sz, int unmmap_ttf)
{
  int thread_cnt = atomic_read(&myproc()->tg.thread_cnt);
  uvmunmap(pagetable, TRAMPOLINE, 1, 0);
  uvmunmap(pagetable, SIGRETURN, 1, 0);
  // uvmunmap(pagetable, TRAPFRAME, 1, 0);

  // and unmap the thread's trapframe
  if(unmmap_ttf)
    for (int i = 0; i < thread_cnt; i++) {
      uvmunmap(pagetable, THREAD_TRAPFRAME(i), 1, 0);
    }
  uvmfree(pagetable, sz);
}

void
userinit(void)
{
  struct proc *p;
  struct tcb *t;
  p = create_proc(); // with a group leader thread
  t = p->tg.group_leader;

  if(p == 0)
    panic("userinit: create_proc failed");

  initproc = p;
  // struct tcb* t = p->tg.group_leader;

  // allocate one user page and copy initcode's instructions
  // and data into it.
  uint64 sz = PGROUNDUP(initcode_len);
  uvmfirst(p->mm.pagetable, initcode, initcode_len);

  uint64 sz1;
  if((sz1 = uvmalloc(p->mm.pagetable, sz, sz + 8 * PGSIZE, PTE_W)) == 0) {
    panic("userinit: uvmalloc failed");
  }
  sz = sz1;
  uvmclear(p->mm.pagetable, sz - 8 * PGSIZE); // clear the stack guard page  

  p->sz = sz; // TODO: how large?? maybe bug here

#ifdef __DEBUG_USERINIT
  Log("userinit: proc %d, pagetable %p, sz %p, initcode_len %p, sz - 64 * PGSIZE: %p", 
      p->pid, p->mm.pagetable, sz, initcode_len, sz - 64 *PGSIZE);
#endif

  // prepare for the very first "return" from kernel to user.
#ifdef __ARCH_RISCV
  t->trapframe->epc = 0;      // user program counter
#else
  t->trapframe->era = 0;
#endif
  t->trapframe->sp = sz;  // user stack pointer
  // Log("userinit trapframe: %p", t->trapframe);
  safestrcpy(p->name, "initcode", sizeof(p->name));
  safestrcpy(p->tg.group_leader->name, "/init-0", 10);
  sighandinit(t); // init the signal handler
  // p->state = RUNNABLE; 
  tcb_q_change_state(t, TCB_RUNNABLE);

  release(&p->lock);
}

int
growproc(int n)
{
  uint64 sz;
  struct proc *p = myproc();

  sz = p->sz;
  if(n > 0){
    if((sz = uvmalloc(p->mm.pagetable, sz, sz + n, PTE_W)) == 0) {
      return -1;
    }
  } else if(n < 0){
    sz = uvmdealloc(p->mm.pagetable, sz, sz + n);
  }
  p->sz = sz;
  return 0;
}

int
fork(void)
{
  int i, pid;
  struct proc *np;
  struct proc *p = myproc();
  // struct tcb  *t = mythread();
  // Allocate process.
  // return with np->lock held
  // if((np = allocproc()) == 0){
  //   return -1;
  // }
  // if((t = alloc_thread(thread_forkret)) == 0) {
  //   freeproc(np);
  //   return -1;
  // }

  // // make the allocated thread be the group leader
  // proc_join_thread(np, t, NULL);
  if((np = create_proc()) == 0) {
    return -1;
  }
  if(uvmcopy(p->mm.pagetable, np->mm.pagetable, p->sz) < 0){
    freeproc(np);
    release(&np->lock);
    return -1;
  }
  np->sz = p->sz;

  // copy vma
  acquire(&p->mm.lock);
  acquire(&np->mm.lock);
  proc_copy_vma(p, np);
  release(&np->mm.lock);
  release(&p->mm.lock);

  // TODO: let's just copy the leader thread right now
  // copy saved user registers.
  *(np->tg.group_leader->trapframe) = *(p->tg.group_leader->trapframe);

  // Cause fork to return 0 in the child.
  np->tg.group_leader->trapframe->a0 = 0;

  // increment reference counts on open file descriptors.
  // child process "open" the files
  for(i = 0; i < NOFILE; i++)
    if(p->ofile[i]) {
      np->ofile[i] = filedup(p->ofile[i]);
      np->ofile_cnt++;
  }
  safestrcpy(np->name, p->name, sizeof(p->name));
  sighandinit(np->tg.group_leader); // init the signal handler
  pid = np->pid;
  strncpy(np->cinfo.path, p->cinfo.path, MAXPATH);
  // release(&np->tg.group_leader->lock);
  release(&np->lock);

  acquire(&wait_lock);
  np->parent = p;
  release(&wait_lock);

  acquire(&p->lock);
  append_child(p, np);
  release(&p->lock);

  // acquire(&np->lock);
  // np->state = RUNNABLE;
  // change the leader thread's state
  // acquire(&np->tg.lock);
  acquire(&np->tg.group_leader->lock);
  tcb_q_change_state(np->tg.group_leader, TCB_RUNNABLE);
  release(&np->tg.group_leader->lock);
  // release(&np->tg.lock);
  // release(&np->lock);

  return pid;
}

int do_clone(int flags, uint64 stack, uint64 ptid, uint64 tls, uint64 ctid)
{
  int i, pid;
  struct proc *np = NULL;
  struct proc *p = myproc();
  struct tcb *t = NULL;

  if(flags & CLONE_THREAD) {
    // if CLONE_THREAD, we just create a new thread in the same process
#ifdef __DEBUG_DO_CLONE
    printf("CLONE_THREAD\n");
#endif
    if((t = alloc_thread(thread_forkret)) == 0)
      return -1; 
    if(proc_join_thread(p, t, NULL) < 0) {
      free_thread(t);
      return -1;
    }
  } else {
    // allocate a process
    if((np = create_proc()) == 0) {
      return -1;
    }
    t = np->tg.group_leader;
  }
  // TODO: let's just copy the leader thread right now
  // copy saved user registers.
  *(t->trapframe) = *(p->tg.group_leader->trapframe);
  // Cause fork to return 0 in the child.
  t->trapframe->a0 = 0;

  if(flags & CLONE_SETTLS) {
#ifdef __DEBUG_DO_CLONE
    printf("CLONE_SETTLS\n");
#endif
    t->trapframe->tp = tls; // set the tp register
  }
  if(flags & CLONE_CHILD_SETTID) {
#ifdef __DEBUG_DO_CLONE
    printf("CLONE_CHILD_SETTID\n");
#endif
    if(copyout(p->mm.pagetable, ctid, (char *)&t->tid, sizeof(t->tid)) < 0) {
      goto bad;
    }
    t->set_child_tid = ctid; // for debug
  }
  if(flags & CLONE_CHILD_CLEARTID) {
#ifdef __DEBUG_DO_CLONE
    printf("CLONE_CHILD_CLEARTID\n");
#endif
    // clear when exit
    t->clear_child_tid = ctid;
  }
  if(stack) {
#ifdef __DEBUG_DO_CLONE
    printf("set stack to %p\n", stack);
#endif
    t->trapframe->sp = stack;
  }
  if(flags & CLONE_SIGHAND) {
#ifdef __DEBUG_DO_CLONE
    printf("CLONE_SIGHAND\n");
#endif
    t->sigs = p->tg.group_leader->sigs; // share the signal handler
    atomic_add_return(&t->sigs->ref, 1); // increment the reference count
  } else {
    sighandinit(t); // init the signal handler
  }
  if(flags & CLONE_PARENT_SETTID) {
#ifdef __DEBUG_DO_CLONE
    printf("CLONE_PARENT_SETTID\n");
#endif
    // set the parent tid
    if(copyout(p->mm.pagetable, ptid, (char *)&t->tid, sizeof(t->tid)) < 0) {
      goto bad;
    }
  }
  if(np == NULL) {
    // if np is NULL, we are just creating a thread
    tcb_q_change_state(t, TCB_RUNNABLE);
    release(&t->lock);
    return t->tid; // return the thread id
  }

  /*
    create a process
  */
  if(flags & CLONE_VM) {
#ifdef __DEBUG_DO_CLONE
    printf("CLONE_VM\n");
#endif
    np->mm.pagetable = p->mm.pagetable; // share the same pagetable
  } else {
    if(uvmcopy(p->mm.pagetable, np->mm.pagetable, p->sz) < 0){
      freeproc(np);
      release(&np->lock);
      return -1;
    }
  }
  // just not support right now
  if(flags & CLONE_FS) {
#ifdef __DEBUG_DO_CLONE
    printf("CLONE_FS\n");
#endif
  }
  if(flags & CLONE_FILES) {
#ifdef __DEBUG_DO_CLONE
    printf("CLONE_FILES\n");
#endif
  }
  if(proc_copy_vma(p, np) < 0) {
    freeproc(np);
    release(&np->lock);
    return -1;
  }
  np->sz = p->sz;
#ifdef __DEBUG_DO_CLONE
  Log("do_clone: old proc %d, sz %p, oldt->trapframe->sp %p", p->pid, p->sz, p->tg.group_leader->trapframe->sp);
  Log("do_clone: np %d, sz %p, t->trapframe->sp %p", np->pid, np->sz, t->trapframe->sp);
  Log("flags = %p ", flags);
#endif
  // increment reference counts on open file descriptors.
  // child process "open" the files
  for(i = 0; i < NOFILE; i++)
    if(p->ofile[i]) {
      np->ofile[i] = filedup(p->ofile[i]);
      np->ofile_cnt++;
    }

  safestrcpy(np->name, p->name, sizeof(p->name));

  pid = np->pid;
  strncpy(np->cinfo.path, p->cinfo.path, MAXPATH);

  release(&np->lock);

  acquire(&wait_lock);
  np->parent = p;
  release(&wait_lock);

  acquire(&p->lock);
  append_child(p, np);
  release(&p->lock);

  acquire(&t->lock);
  tcb_q_change_state(t, TCB_RUNNABLE);
  release(&t->lock);

  return pid;

bad:
  printf("bad \n");
  if(np) {
    freeproc(np);
  }
  if(t) {
    free_thread(t);
  }
  return -1;
}

void
reparent(struct proc *p)
{
  struct proc *pp;

  for(pp = proc; pp < &proc[NPROC]; pp++){
    if(pp->parent == p){
      pp->parent = initproc;
      thread_wakeup_chan(initproc);
    }
  }
}

void proc_exit(int status)
{
  struct proc *p = myproc();
  // struct tcb *t = mythread();
  if(p == initproc)
    panic("init exiting");

  // Close all open files.
  for(int fd = 0; fd < NOFILE; fd++){
    if(p->ofile[fd]){
      struct file *f = p->ofile[fd];
      if(f->ref > 0)
        fileclose(f, 1);
      p->ofile[fd] = 0;
    }
  }
  freeprocvm(p);

  memset(&p->cinfo, 0, sizeof(p->cinfo));

  acquire(&wait_lock);

  acquire(&p->lth_exitlock);
  // Give any children to init.
  reparent(p);

  // Parent might be sleeping in wait().
  thread_wakeup_chan(p->parent);

  acquire(&p->lock);

  p->xstate = status;
  p->xstate <<= 8; // shift to high byte
  pcb_q_change_state(p, ZOMBIE);

  siginfo_t info;
  struct proc *pp = p->parent;
  signal_info_init(SIGCHLD, &info, 1);
  acquire(&pp->tg.group_leader->lock);
  thread_send_signal(pp->tg.group_leader, &info); // send SIGCHLD to the group leader thread
  release(&pp->tg.group_leader->lock);

  release(&wait_lock);

  // Jump into the scheduler, never to return.
  // thread_sched();
  // panic("zombie exit");
}

int
wait_one(uint64 addr)
{
  struct proc *pp;
  int havekids, pid;
  struct proc *p = myproc();
  // struct tcb *t = mythread();

  acquire(&wait_lock);    

  for(;;){
    // Scan through table looking for exited children.
    havekids = 0;
    for(pp = proc; pp < &proc[NPROC]; pp++){
      if(pp->parent == p){
        // make sure the child isn't still in exit() or swtch().
        acquire(&pp->lock);

        havekids = 1;
        if(pp->state == ZOMBIE){
          // Found one.
          pid = pp->pid;
          if(addr != 0 && copyout(p->mm.pagetable, addr, (char *)&pp->xstate,
                                  sizeof(pp->xstate)) < 0) {
            release(&pp->lock);
            release(&wait_lock);
            return -1;
          }
          freeproc(pp);
          release(&pp->lock);
          release(&wait_lock);
          return pid;
        }
        release(&pp->lock);
      }
    }

    // No point waiting if we don't have any children. 
    if(!havekids || proc_killed(p)){
      release(&wait_lock);
      return -1;
    }

#ifdef __DEBUG_WAIT
    Info("thread %d wait, ready to sleep\n", mythread()->tid);
#endif
    // Wait for a child to exit.
    thread_sleep(p, &wait_lock, NULL);  //DOC: wait-sleep
#ifdef __DEBUG_WAIT
    Info("thread %d wait, waked up\n", mythread()->tid);
#endif
  }
}

pid_t wait4(pid_t pid, uint64 pstatus, int options) {
  struct proc *pp;
  int havekids;
  struct proc *p = myproc();

  acquire(&wait_lock);

  for(;;){
    // Scan through table looking for exited children.
    havekids = 0;
    for(pp = proc; pp < &proc[NPROC]; pp++){
      if(pp->parent == p && pid == pp->pid){
        // make sure the child isn't still in exit() or swtch().
        acquire(&pp->lock);

        havekids = 1;
        if(pp->state == ZOMBIE){
          // Found target child process.
          if(pstatus != 0 && copyout(p->mm.pagetable, pstatus, (char *)&pp->xstate,
                                  sizeof(pp->xstate)) < 0) {
            release(&pp->lock);
            release(&wait_lock);
            return -1;
          }
          freeproc(pp);
          release(&pp->lock);
          release(&wait_lock);
          return pid;
        }
        release(&pp->lock);
      }
    }

    // No point waiting if we don't have any children.
    if(!havekids || proc_killed(p)){
      release(&wait_lock);
      return -1;
    }

    // WNOHANG: return immediately if no child has exited.
    if(options & WNOHANG) {
      release(&wait_lock);
      return 0;
    }
    // Wait for a child to exit.
    // TODO: how to wait for a specific child process to exit??
    // TODO: bug here: any child process will wake up this parent process
    thread_sleep(p, &wait_lock, NULL);  //DOC: wait-sleep
  }

}

pid_t waitpid(pid_t pid, uint64 wstatus, int options) {
  if(pid < -1 || pid == 0) {
    panic("waitpid: not support pid < -1 || pid == 0 right now!, for no process group!");
  }
  if(pid == -1 && options == 0) {
    return wait_one(wstatus);
  } else {
    return wait4(pid, wstatus, options);
  }
}

int
proc_kill(int pid, sig_t sig)
{
  struct proc *p;

  if(pid > 0) {
    for(p = proc; p < &proc[NPROC]; p++){
      acquire(&p->lock);
      if(p->pid == pid){
  #ifdef __DEBUG_PROC_KILL
        Log("kill: pid %d, name %s, sig %d ", p->pid, p->name, sig);
  #endif //__DEBUG_KILL
        proc_sendsignal_all_thread(p, sig, 0); // send signal to all threads in the process
        release(&p->lock);
        return 0;
      }
      release(&p->lock);
    }
  } else {
    Warn("proc_kill: pid <= 0, not support right now!");
  }
  return -1;
}

void
proc_setkilled(struct proc *p)
{
  acquire(&p->lock);
  p->killed = 1;
  release(&p->lock);
}

int
proc_killed(struct proc *p)
{
  int k;

  acquire(&p->lock);
  k = p->killed;
  release(&p->lock);
  return k;
}

int
either_copyout(int user_dst, uint64 dst, void *src, uint64 len)
{
  struct proc *p = myproc();
  if(user_dst){
    return copyout(p->mm.pagetable, dst, src, len);
  } else {
    memmove((char *)dst, src, len);
    return 0;
  }
}

int
either_copyin(void *dst, int user_src, uint64 src, uint64 len)
{
  struct proc *p = myproc();
  if(user_src){
    return copyin(p->mm.pagetable, dst, src, len);
  } else {
    memmove(dst, (char*)src, len);
    return 0;
  }
}

