  static char *states[] = {
  [UNUSED]    "unused", 
  [USED]      "used",
  // [SLEEPING]  "sleep ",
  // [RUNNABLE]  "runble",
  // [RUNNING]   "run   ",
  [ZOMBIE]    "zombie"
  };
  struct proc *p;
