uint64 sys_brk(void) {
  uint64 addr;
  uint64 oldsz;

  argaddr(0, &addr);
  #ifdef __DEBUG_BRK
  Log("[sys_brk] %p", addr);
  Log("[sys_brk] oldsize %p", myproc()->sz);
  #endif

  if(addr >= MAXVA || addr >= BRKTOP) {
    Warn("brk %p failed\n", addr);
    return -1;
  }
  oldsz = myproc()->sz;

  if(addr == 0) {
    return oldsz;
  }
  if(addr > oldsz) {
    if (growproc(addr - oldsz) < 0)
      return -1;
    else
      return myproc()->sz;
  } 
  return oldsz;

}

