sys_sleep(void)
{
  int n;
  uint ticks0;

  struct proc *p = myproc();
  struct tcb *t = mythread();

  argint(0, &n);
  acquire(&tickslock);
  ticks0 = ticks;
  while(ticks - ticks0 < 10 * n){
    if(proc_killed(p) || thread_killed(t)){
      release(&tickslock);
      return -1;
    }
    thread_sleep(&ticks, &tickslock, NULL);
  }
  release(&tickslock);
  return 0;
}

